export function runRoundChecks(root: string, log: LogFn): void {
  console.log('\n## Round Checks (declarative)')
  let passed = 0
  let failed = 0

  // Existence checks
  for (const check of EXISTENCE_CHECKS) {
    const fullPath = join(root, check.file)
    if (existsSync(fullPath)) {
      log('pass', check.round, check.passMsg)
      passed++
    } else {
      log('warning', check.round, check.failMsg || `${check.file} 파일 없음`, check.failFile)
      failed++
    }
  }

  // Single-file keyword checks
  for (const check of ROUND_CHECKS) {
    const src = readCached(root, check.file)
    if (src === null) {
      log(check.failLevel ?? 'warning', check.round, check.failMsg || `${check.file} 파일 없음`, check.failFile)
      failed++
      continue
    }

    const op = check.operator ?? 'and'
    const ok = op === 'and'
      ? check.keywords.every(k => src.includes(k))
      : check.keywords.some(k => src.includes(k))

    if (ok) {
      log('pass', check.round, check.passMsg)
      passed++
    } else {
      log(check.failLevel ?? 'warning', check.round, check.failMsg, check.failFile)
      failed++
    }
  }

  // Multi-file keyword checks (all files must pass)
  for (const check of MULTI_FILE_CHECKS) {
    const allOk = check.files.every(f => {
      const src = readCached(root, f.file)
      if (src === null) return false
      const op = check.operator ?? 'and'
      return op === 'and'
        ? f.keywords.every(k => src.includes(k))
        : f.keywords.some(k => src.includes(k))
    })

    if (allOk) {
      log('pass', check.round, check.passMsg)
      passed++
    } else {
      log(check.failLevel ?? 'warning', check.round, check.failMsg, check.failFile)
      failed++
    }
  }

  const total = EXISTENCE_CHECKS.length + ROUND_CHECKS.length + MULTI_FILE_CHECKS.length
  console.log(`  Round checks: ${passed} passed, ${failed} failed (total ${total})`)
}
